package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testValueOf_withValidPredefinedFormats() throws Exception {
        // Use reflection to set CSVFormat.Predefined enum to support valueOf call
        Class<?> predefinedClass = Class.forName("org.apache.commons.csv.CSVFormat$Predefined");
        Field[] fields = CSVFormat.class.getDeclaredFields();
        // Ensure the predefined constants exist
        assertNotNull(CSVFormat.DEFAULT);
        assertNotNull(CSVFormat.RFC4180);
        assertNotNull(CSVFormat.EXCEL);
        assertNotNull(CSVFormat.TDF);
        assertNotNull(CSVFormat.MYSQL);

        // Test predefined formats by name
        assertSame(CSVFormat.DEFAULT, CSVFormat.valueOf("DEFAULT"));
        assertSame(CSVFormat.RFC4180, CSVFormat.valueOf("RFC4180"));
        assertSame(CSVFormat.EXCEL, CSVFormat.valueOf("EXCEL"));
        assertSame(CSVFormat.TDF, CSVFormat.valueOf("TDF"));
        assertSame(CSVFormat.MYSQL, CSVFormat.valueOf("MYSQL"));
    }

    @Test
    void testValueOf_withCaseInsensitive() {
        // Check case insensitive matching
        assertSame(CSVFormat.DEFAULT, CSVFormat.valueOf("default"));
        assertSame(CSVFormat.RFC4180, CSVFormat.valueOf("rfc4180"));
        assertSame(CSVFormat.EXCEL, CSVFormat.valueOf("excel"));
        assertSame(CSVFormat.TDF, CSVFormat.valueOf("tdf"));
        assertSame(CSVFormat.MYSQL, CSVFormat.valueOf("mysql"));
    }

    @Test
    void testValueOf_withInvalidFormat_throwsException() {
        // Expect IllegalArgumentException for unknown format name
        assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf("UnknownFormat"));
        assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf(""));
        assertThrows(NullPointerException.class, () -> CSVFormat.valueOf(null));
    }
}
